:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --text: #2c3e50;
  --border: #e0e0e0;
  --safe: #27ae60;
  --danger: #c0392b;
  --warning: #f39c12;
  --neutral: #7f8c8d;
}

body {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: var(--bg-color);
  color: var(--text);
  padding: 20px;
  margin: 0;
}

header {
  text-align: center;
  margin-bottom: 30px;
}

header h1 {
  margin: 0;
  color: var(--text);
}

header p {
  margin: 5px 0 0;
  color: var(--neutral);
}

/* Grid Layout for Top Cards */
.comparison-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
  margin-bottom: 25px;
}

.card {
  background: var(--card-bg);
  border-radius: 8px;
  padding: 20px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
  border-top: 5px solid;
}

.policy-card {
  border-top-color: var(--safe);
}

.reality-card {
  border-top-color: var(--danger);
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
  border-bottom: 1px solid var(--border);
  padding-bottom: 10px;
}

.card-header h3 {
  margin: 0;
  font-size: 1.1rem;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.stat-row {
  display: flex;
  justify-content: space-around;
  text-align: center;
}

.stat label {
  display: block;
  font-size: 0.85rem;
  color: var(--neutral);
  margin-bottom: 5px;
  text-transform: uppercase;
}

.stat .value {
  font-size: 1.8rem;
  font-weight: 800;
}

.value.neutral {
  color: var(--neutral);
  font-size: 1.2rem;
  margin-top: 8px;
}

.value.safe {
  color: var(--safe);
}

.value.danger {
  color: var(--danger);
}

.value.warning {
  color: var(--warning);
  font-size: 1.5rem;
  margin-top: 5px;
}

/* Badges */
.badge {
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 0.8rem;
  font-weight: bold;
  color: white;
}

.badge-success {
  background-color: var(--safe);
}

.badge-danger {
  background-color: var(--danger);
}

.badge-critical {
  background-color: var(--danger);
  border: 1px solid #a93226;
}

/* Verdict Banner - Adjusted to fit text width */
.verdict-banner {
  background: var(--card-bg);
  text-align: center;
  padding: 15px 30px; /* Reduced vertical padding, kept horizontal for look */
  border-radius: 8px;
  /* NEW PROPERTIES START */
  width: fit-content; /* Shrinks width to match the text inside */
  margin: 0 auto 25px auto; /* 'auto' on left/right centers the shrinked card */
  max-width: 90%; /* Prevents it from touching edges on small screens */
  /* NEW PROPERTIES END */
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
  border: 1px solid var(--border);
}

.verdict-critical {
  background-color: #fadbd8;
  border: 2px solid var(--danger);
  color: #922b21;
}

.verdict-critical h2 {
  margin: 0;
}

.verdict-safe {
  background-color: #d5f5e3;
  border: 2px solid var(--safe);
  color: #1e8449;
}

/* Conflict Table */
.conflict-section {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 15px;
}

th {
  text-align: left;
  color: var(--neutral);
  border-bottom: 2px solid var(--border);
  padding: 10px;
  font-size: 0.9rem;
}

td {
  padding: 12px 10px;
  border-bottom: 1px solid var(--border);
  font-size: 1rem;
}

.conflict-text {
  color: var(--danger);
  font-weight: 600;
}

code {
  background: #eee;
  padding: 2px 4px;
  border-radius: 3px;
  font-family: monospace;
}

.verdict-banner {
  padding: 20px;
  border-radius: 8px;
  margin-bottom: 20px;
  text-align: center;
  transition: all 0.3s ease;
}

.verdict-critical {
  background-color: #f8d7da;
  color: #721c24;
  border: 2px solid #f5c6cb;
}

.verdict-safe {
  background-color: #d4edda;
  color: #155724;
  border: 2px solid #c3e6cb;
}

.conflict-text {
  font-size: 0.85rem;
  color: #e74c3c;
}

.badge-success {
  background: #2ecc71;
  color: white;
}

.badge-danger {
  background: #e74c3c;
  color: white;
}

