appsmith.onReady(() => {
  const model = appsmith.model;
  renderGapAnalysis(model);
});
appsmith.onModelChange(newModel => {
  renderGapAnalysis(newModel);
});
function renderGapAnalysis(model) {
  if (!model) return;

  // --- 1. Policy Context (From Policy Data) ---
  const policy = model.policy_data?.data || {};
  const hasNotice = !!policy.policy_metadata;
  const statedStatus = policy.policy_metadata?.status || "Unknown";
  const allowedThirdParties = Object.keys(policy.third_party_egress_rules || {});

  // --- 2. Reality Analysis (Enhanced AI & Privacy Detection) ---
  const networkEvents = model.networkEvents || [];
  const aiVendors = ["openai", "anthropic", "claude", "mistral", "googletagmanager", "googlesyndication"];
  let shadowAICount = 0;
  let totalExfiltratedSize = 0;
  const leakageEvents = [];
  networkEvents.forEach(event => {
    if (event.method === "Network.requestWillBeSent") {
      const urlStr = event.params.request.url;
      let domain = "unknown";
      try {
        domain = new URL(urlStr).hostname;
      } catch (e) {
        domain = urlStr;
      }
      const isAIVendor = aiVendors.some(vendor => domain.includes(vendor));
      if (isAIVendor) {
        shadowAICount++;
        const headers = event.params.request.headers || {};
        const size = parseInt(headers['Content-Length'] || headers['content-length'] || 0);
        totalExfiltratedSize += size;

        // --- AI RISK LOGIC ---
        let riskCategory = "General Metadata";
        let contradiction = "Section 3 (Unauthorized Egress)";

        // Link domain to specific policy violations
        if (domain.includes("googlesyndication")) {
          riskCategory = "Ad Profiling / Hashed ID";
          contradiction = "Third Party Egress Rule (Advertising)";
        } else if (size > 2000) {
          // Heuristic: Large POSTs to AI domains likely contain prompt/context data
          riskCategory = "LLM Training Ingestion";
          contradiction = "AI Audit: No Training Clause";
        }
        leakageEvents.push({
          domain: domain,
          type: "Shadow AI Egress",
          risk: riskCategory,
          contradiction: contradiction,
          size: size
        });
      }
    }
  });

  // --- 3. Update UI ---

  // A. Policy Card
  document.getElementById('notice-status').textContent = hasNotice ? "Effective: " + policy.policy_metadata.effective_date : "No Notice";
  document.getElementById('stated-purpose').textContent = "Regulated: " + allowedThirdParties.join(", ");
  const policyBadge = document.getElementById('policy-badge');
  policyBadge.textContent = statedStatus;
  policyBadge.className = hasNotice ? "badge badge-success" : "badge badge-danger";

  // B. Reality Card
  document.getElementById('leak-count').textContent = shadowAICount;
  document.getElementById('exfiltration-volume').textContent = (totalExfiltratedSize / 1024).toFixed(1) + " KB";
  const realityBadge = document.getElementById('reality-badge');
  realityBadge.textContent = shadowAICount > 0 ? "Compliance Gap" : "Verified Safe";
  realityBadge.className = shadowAICount > 0 ? "badge badge-danger" : "badge badge-success";

  // C. The Verdict (The "So What?")
  const verdictBanner = document.getElementById('verdict-banner');
  const h2 = verdictBanner.querySelector('h2');
  if (shadowAICount > 0) {
    verdictBanner.className = "verdict-banner verdict-critical";
    h2.innerHTML = `⚠️ POLICY MISMATCH: ${shadowAICount} UNSANCTIONED DATA FLOWS<br>
                        <span style='font-size:0.9rem; font-weight:normal'>Observed traffic to <b>AI/Ad Vendors</b> is not authorized under the 2020 Policy Framework.</span>`;
  } else {
    verdictBanner.className = "verdict-banner verdict-safe";
    h2.textContent = "✅ Operational Reality Aligns with Policy";
  }

  // D. Table
  const tbody = document.getElementById('conflict-body');
  tbody.innerHTML = "";
  leakageEvents.forEach(leak => {
    const row = document.createElement('tr');
    row.innerHTML = `
            <td><code>${leak.domain}</code></td>
            <td>${leak.type}</td>
            <td><strong style="color:#c0392b">${leak.risk}</strong><br><small>${(leak.size / 1024).toFixed(1)} KB</small></td>
            <td class="conflict-text"><strong>Violation:</strong> ${leak.contradiction}</td>
        `;
    tbody.appendChild(row);
  });
}

